  /**
   * 格式化日期为更好的显示格式
   * @param {string} dateString - ISO日期字符串
   * @returns {string} 格式化的日期
   */
  static formatDate(dateString) {
    if (!dateString) return 'N/A';
    try {
      const date = new Date(dateString);

      // 检查日期是否有效
      if (isNaN(date.getTime())) {
        return dateString; // 如果无效，则返回原始字符串
      }

      // 格式化为 '15th December, 2023' 这样的格式
      const options = {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      };
      let formatted = date.toLocaleDateString('en-US', options);

      // 添加序数后缀 (1st, 2nd, 3rd, 4th 等)
      const day = date.getDate();
      const suffix = this.getOrdinalSuffix(day);

      // 替换日期中的数字为带有序数后缀的版本
      formatted = formatted.replace(String(day), `${day}${suffix}`);
      return formatted;
    } catch (error) {
      console.error('格式化日期时出错:', error);
      return dateString;
    }
  }

  /**
   * 获取数字的序数后缀 (st, nd, rd, th)
   * @param {number} n - 数字
   * @returns {string} 序数后缀
   */
  static getOrdinalSuffix(n) {
    if (n > 3 && n < 21) return 'th'; // 11th, 12th, 13th, ...
    switch (n % 10) {
      case 1:
        return 'st';
      case 2:
        return 'nd';
      case 3:
        return 'rd';
      default:
        return 'th';
    }
  }

  /**
   * 缩短哈希值为更友好的显示格式
   * @param {string} hash - 完整哈希值
   * @returns {string} 缩短的哈希值
   */
  static shortenHash(hash) {
    if (!hash) return 'N/A';

    // 如果哈希值很长，只保留前6位和后6位
    if (hash.length > 15) {
      return `${hash.substring(0, 6)}...${hash.substring(hash.length - 6)}`;
    }
    return hash;
  }

  /**
   * 添加水印到PDF文档
   * @param {jsPDF} doc - jsPDF文档对象
   */
  static addWatermark(doc) {
    // 获取页面尺寸
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();

    // 设置水印样式
    doc.setTextColor(0, 48, 135); // 深蓝色
    doc.setGState(new doc.GState({
      opacity: 0.04
    }));
    doc.setFontSize(120);
    doc.setFont('helvetica', 'bold');

    // 添加旋转的"SIU"水印
    doc.saveGraphicsState();
    doc.translate(pageWidth / 2, pageHeight / 2);
    doc.rotate(-30);
    doc.text('SIU', 0, 0, {
      align: 'center'
    });
    doc.restoreGraphicsState();

    // 添加校徽水印
    try {
      // 使用校徽作为水印 - 修改为SVG
      const logoPath = '/images/logo/logo.svg'; // <--- 修改路径为 .svg
      const baseUrl = window.location.origin;
      const logoUrl = `${baseUrl}${logoPath}`;

      // 设置更低的不透明度
      doc.setGState(new doc.GState({
        opacity: 0.03
      }));

      // 添加大尺寸校徽水印在背景中 - 修改格式为SVG
      doc.addImage(logoUrl, 'SVG', pageWidth / 2 - 100, pageHeight / 2 - 100, 200, 200); // <--- 修改格式为 'SVG'
    } catch (error) {
      console.error('添加校徽水印失败:', error);
      // 水印加载失败时不做任何处理，保留文字水印

      // 如果加载失败，绘制一个简单的替代水印
      try {
        doc.setGState(new doc.GState({
          opacity: 0.02
        }));
        doc.setDrawColor(0, 48, 135); // 深蓝色
        doc.setFillColor(0, 48, 135); // 深蓝色
        doc.circle(pageWidth / 2, pageHeight / 2, 80, 'S');
      } catch (backupError) {
        console.error('绘制备用水印也失败:', backupError);
      }
    }

    // 恢复默认样式
    doc.setGState(new doc.GState({
      opacity: 1.0
    }));
  }

