        const signature1Url = `${baseUrl}${signature1Path}`;
        doc.addImage(signature1Url, 'PNG', signature1X - 40, signatureY - 20, 80, 30);
      } catch (error) {
        // 如果图片加载失败，画一条线作为替代
        doc.setDrawColor(0, 0, 0);
