      });
      doc.text('Prof. Dr. James Carpenter', signature2X, signatureY + 15, {
        align: 'center'
      });
      doc.setFontSize(10);
      doc.setFont('times', 'normal');
      doc.text('University President', signature1X, signatureY + 25, {
