    });
    doc.setFontSize(7);
    doc.text('ESTABLISHED 2005', pageWidth / 2, pageHeight - 60, {
      align: 'center'
    });

    // 添加区块链验证图标 - 使用更清晰的设计
    const iconX = 40;
    const iconY = pageHeight - 75;

