      doc.setFontSize(size / 6);
      doc.setFont('times', 'bold');
      doc.text('STRATFORD', x, y - size / 10, {
        align: 'center'
      });
      doc.text('UNIVERSITY', x, y + size / 10, {
        align: 'center'
      });
