import { jsPDF } from 'jspdf';
import i18next from 'i18next';
import certificateConfig from '../config/certificateTemplates.json';
import QRCode from 'qrcode';

// 导入crypto模块（如果在Node.js环境中）或使用浏览器兼容的哈希函数
// 浏览器兼容的哈希函数
function sha256(str) {
  return crypto.subtle.digest('SHA-256', new TextEncoder().encode(str))
    .then(hashBuffer => {
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
      return hashHex;
    });
}

/**
 * 证书生成服务 - 用于创建可下载的证书PDF
 */
class CertificateGenerator {
  /**
   * 根据证书数据生成PDF证书
   * @param {Object} certificate - 证书数据
   * @returns {Promise<Blob>} 返回PDF Blob
   */
  static generateCertificatePDF(certificate) {
    return new Promise((resolve, reject) => {
      try {
        // 获取当前语言
        const currentLanguage = i18next.language;
        const isEnglish = currentLanguage === 'en' || currentLanguage.startsWith('en-');

        // 创建PDF文档 (A4横向)
        const doc = new jsPDF({
          orientation: 'landscape',
          unit: 'mm',
          format: 'a4',
        });

        // 设置文档属性
        doc.setProperties({
          title: `${certificate.name} - ${isEnglish && certificate.english_course ? certificate.english_course : certificate.course} Certificate`,
          subject: 'Stratford International University Certificate',
          author: 'Stratford International University',
          keywords: 'certificate, education, diploma, blockchain, verified',
          creator: 'SIU Certificate System',
        });

        // 添加水印
        this.addWatermark(doc);

        // 加载证书SVG作为背景并处理后续操作
        this.loadSVGBackground(doc, certificate)
          .then(async () => {
            // 添加证书详细信息
            this.addCertificateDetails(doc, certificate);

            // 生成区块链验证哈希
            const blockchainHash = await this.generateBlockchainHash(certificate);
            certificate.blockchainHash = blockchainHash;

            // 添加QR码 (用于验证)
            await this.addVerificationQR(doc, certificate);

            // 添加签名图片
            await this.addSignatureImages(doc, certificate);

            // 添加装饰元素和装饰花边
            this.addDecorativeElements(doc);

            // 生成PDF并返回
            const pdfBlob = doc.output('blob');
            resolve(pdfBlob);
          })
          .catch(error => {
            console.error('加载SVG背景失败:', error);
            reject(error);
          });
      } catch (error) {
        console.error('PDF生成错误:', error);
        reject(error);
      }
    });
  }

  /**
   * 预览证书 - 将证书数据填充到模板中
   * @param {Object} certificate - 证书数据
   * @returns {Promise<string>} 处理后的证书URL
   */
  static async previewCertificate(certificate) {
    try {
      // 如果证书已经处理过，直接返回
      if (certificate.processedImage) {
        return certificate.processedImage;
      }

      // 检查certificate.image是否有效
      if (!certificate.image) {
        console.error('证书没有图像路径');
        return this.generateErrorImage(certificate);
      }

      // 加载证书模板
      const response = await fetch(certificate.image);
      
      if (!response.ok) {
        console.error(`加载证书模板失败: ${response.status} ${response.statusText}`);
        return this.generateErrorImage(certificate);
      }

      // 获取SVG内容
      let svgContent = await response.text();

      // 修改SVG尺寸确保足够大以显示清晰
      svgContent = svgContent.replace(/<svg([^>]*)>/, '<svg$1 width="1200" height="900" preserveAspectRatio="xMidYMid meet">');
      
      // 增加文本元素的字体粗细和大小，提高可见度
      svgContent = svgContent.replace(/font-size="(\d+)"/g, (match, size) => {
        const newSize = Math.floor(parseInt(size) * 1.2); // 增加20%的字体大小
        return `font-size="${newSize}"`;
      });
      
      // 增加文本元素的填充颜色深度
      svgContent = svgContent.replace(/fill="#[0-9a-fA-F]{6}"/g, (match) => {
        if (match.includes("#FFFFFF") || match.includes("#ffffff")) {
          return match; // 保持白色不变
        } else {
          return 'fill="#000000"'; // 其他颜色全部改为黑色以增加对比度
        }
      });

      // 替换模板中的占位符
      const replacements = {
        '[RECIPIENT NAME]': `${certificate.name || 'Student Name'}`,
        '[PROGRAM/DEGREE]': `${certificate.course || 'Course Name'}`,
        '[DATE]': this.formatDate(certificate.date),
        '[CERTIFICATE-ID]': certificate.certificateId || 'N/A',
        '[HASH]': this.shortenHash(certificate.id),
      };

      // 应用所有替换
      Object.entries(replacements).forEach(([placeholder, value]) => {
        svgContent = svgContent.replace(new RegExp(placeholder, 'g'), value);
      });

      // 增加SVG样式以提高文本清晰度
      svgContent = svgContent.replace('</svg>', '<style>text { paint-order: stroke; stroke: #fff; stroke-width: 0.5px; }</style></svg>');

      // 创建Blob和URL
      const blob = new Blob([svgContent], { type: 'image/svg+xml' });
      const processedImageUrl = URL.createObjectURL(blob);

      // 保存处理后的图像URL
      certificate.processedImage = processedImageUrl;

      console.log('证书SVG处理完成，提高了文本可见度');
      return processedImageUrl;
    } catch (error) {
      console.error('处理证书时出错:', error);
      return this.generateErrorImage(certificate);
    }
  }

  /**
   * 使用证书数据创建证书的PDF
   * @param {Object} certificate - 证书数据对象
   * @returns {Promise<Blob>} PDF Blob对象
   */
  static async createPDF(certificate) {
    try {
      // 如果没有证书，则返回错误
      if (!certificate) {
        throw new Error('证书数据不能为空');
      }

      // 获取证书图像
      const imageUrl = await this.previewCertificate(certificate);
      
      // 如果是错误图像，记录日志但继续生成PDF（用户仍然可以下载错误提示）
      if (certificate._isErrorImage) {
        console.warn(`使用错误占位图生成证书PDF: ${certificate.certificateId}`);
      }

      // 创建PDF文档
      const doc = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4',
        compress: false // 关闭压缩以提高质量
      });

      // 加载图像并添加到PDF
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
          try {
            // 计算图像适应A4页面的尺寸
            const pageWidth = doc.internal.pageSize.getWidth();
            const pageHeight = doc.internal.pageSize.getHeight();
            
            // 在页面上创建白色背景
            doc.setFillColor(255, 255, 255);
            doc.rect(0, 0, pageWidth, pageHeight, 'F');
            
            // 保持图像宽高比，但填满页面
            let imgWidth = pageWidth;
            let imgHeight = (img.height * pageWidth) / img.width;
            
            // 如果高度超出页面，则以高度为基准
            if (imgHeight > pageHeight) {
              imgHeight = pageHeight;
              imgWidth = (img.width * pageHeight) / img.height;
            }
            
            // 居中图像
            const x = (pageWidth - imgWidth) / 2;
            const y = (pageHeight - imgHeight) / 2;
            
            // 将SVG添加到PDF，增加DPI提高质量
            doc.addImage(img.src, 'SVG', x, y, imgWidth, imgHeight, undefined, 'FAST', 300);
            
            // 添加元数据
            doc.setProperties({
              title: `${certificate.name} - ${certificate.course}`,
              subject: 'SIU Certificate',
              author: 'Stratford International University',
              creator: 'SIU Certificate System',
              keywords: 'certificate, diploma, education, university'
            });
            
            // 输出高质量PDF文件
            const pdfBlob = doc.output('blob', {
              compress: false,
              precision: 4
            });
            resolve(pdfBlob);
          } catch (error) {
            console.error('处理PDF时出错:', error);
            reject(error);
          }
        };
        
        img.onerror = (error) => {
          console.error('加载证书图像失败:', error);
          reject(new Error('加载证书图像失败'));
        };
        
        // 设置图像源
        img.src = imageUrl;
      });
    } catch (error) {
      console.error('创建PDF时出错:', error);
      throw error;
    }
  }

  /**
   * 生成错误图像 - 用于在无法加载证书图像时显示
   * @param {Object} certificate - 证书数据
   * @returns {string} 图像URL
   */
  static generateErrorImage(certificate) {
    // 创建一个更专业的SVG，模仿真实证书但显示错误消息
    const svgContent = `
    <svg width="800" height="600" xmlns="http://www.w3.org/2000/svg" role="img" aria-labelledby="certificate-error-title certificate-error-desc">
      <title id="certificate-error-title">Certificate Error</title>
      <desc id="certificate-error-desc">Certificate image is not available for this certificate</desc>
      
      <!-- 使用柔和的背景色和更优雅的设计 -->
      <rect width="800" height="600" fill="#f8f9fa" stroke="#cccccc" stroke-width="2" />
      
      <!-- 添加内边框使其看起来更像证书 -->
