  /**
   * 生成区块链验证哈希
   * @param {Object} certificate - 证书数据
   * @returns {Promise<string>} 哈希值
   */
  static async generateBlockchainHash(certificate) {
    try {
      const data = `${certificate.name}-${certificate.course}-${certificate.date}-${certificate.certificateId}`;
      return await sha256(data);
    } catch (error) {
      console.error('Error generating blockchain hash:', error);
      // Make sure default hash is visible and clearly formatted
      return `SIU-${Math.random().toString(36).substring(2, 10).toUpperCase()}`;
    }
  }

  /**
   * 添加验证用QR码
   * @param {jsPDF} doc - jsPDF文档对象 
   * @param {Object} certificate - 证书数据
   */
  static async addVerificationQR(doc, certificate) {
    try {
      // Generate verification URL
      const baseUrl = window.location.origin;
      const verifyUrl = `${baseUrl}/verify/${certificate.certificateId}`;
      
      // Position QR code on the document (bottom right corner)
      const x = doc.internal.pageSize.getWidth() - 70;
      const y = doc.internal.pageSize.getHeight() - 70;
      
      // Generate QR code with improved options for better visibility
      const qrDataUrl = await QRCode.toDataURL(verifyUrl, {
        margin: 1,
        width: 160,
        color: {
          dark: '#000000',  // Dark QR color
          light: '#FFFFFF'  // Light background
        },
        errorCorrectionLevel: 'H'  // High error correction
      });
      
      // Add QR code to the document with a white background frame
      doc.setFillColor(255, 255, 255);
      doc.rect(x - 5, y - 5, 60, 60, 'F');
      doc.addImage(qrDataUrl, 'PNG', x - 5, y - 5, 60, 60);
      
      // Add QR code label with improved visibility
      doc.setFontSize(8);
      doc.setTextColor(0, 0, 0);  // Black text for visibility
      doc.text('SCAN TO VERIFY', x + 25, y + 65, { align: 'center' });
      
      // Add certificate ID and blockchain hash with improved visibility
      doc.setFontSize(10);
      doc.setTextColor(0, 0, 0);  // Black text
      doc.text(`Certificate ID: ${certificate.certificateId}`, x + 25, y + 75, { align: 'center' });
      
      // Add blockchain hash label with better formatting
      doc.setFontSize(8);
      doc.setTextColor(0, 0, 0);  // Black text
      const hash = certificate.blockchainHash || 'Pending verification';
      // Format the hash to be more readable
      const formattedHash = hash.length > 20 ? `${hash.substring(0, 12)}...${hash.substring(hash.length - 8)}` : hash;
      doc.text(`Verification Hash: ${formattedHash}`, x + 25, y + 82, { align: 'center' });
    } catch (error) {
      console.error('Error adding QR code:', error);
    }
  }

