    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.setFont('times', 'bold');
    doc.text('Blockchain Verified', iconX, iconY + 20, { align: 'center' });
  }
  
  /**
   * 添加大学校徽
   * @param {jsPDF} doc - jsPDF文档对象
   * @param {number} x - 中心X坐标
   * @param {number} y - 中心Y坐标
   * @param {number} size - 校徽尺寸
   */
  static addUniversityLogo(doc, x, y, size) {
    try {
      // 尝试加载校徽图片
      const logoPath = '/images/siu-logo/logo.png';
      const baseUrl = window.location.origin;
      const logoUrl = `${baseUrl}${logoPath}`;
      
      // 添加校徽图片
      doc.addImage(logoUrl, 'PNG', x - size/2, y - size/2, size, size);
    } catch (error) {
      console.error('加载校徽失败:', error);
      
      // 如果加载失败，绘制一个简单的替代校徽
      // 外圆
      doc.setDrawColor(0, 48, 135); // 深蓝色
      doc.setFillColor(0, 48, 135);
      doc.circle(x, y, size/2, 'F');
      
      // 内圆
      doc.setFillColor(255, 255, 255);
      doc.circle(x, y, size/2 - 5, 'F');
      
      // 文字
      doc.setTextColor(0, 48, 135);
      doc.setFontSize(size/6);
      doc.setFont('times', 'bold');
      doc.text('STRATFORD', x, y - size/10, { align: 'center' });
      doc.text('UNIVERSITY', x, y + size/10, { align: 'center' });
    }
  }
  
  /**
   * 绘制星形装饰
   * @param {jsPDF} doc - jsPDF文档对象
   * @param {number} x - 中心X坐标
   * @param {number} y - 中心Y坐标
   * @param {number} outerRadius - 外半径
   * @param {number} innerRadius - 内半径
   * @param {number} r - 红色值 (0-255)
   * @param {number} g - 绿色值 (0-255)
   * @param {number} b - 蓝色值 (0-255)
   * @param {number} alpha - 透明度 (0-1)
   */
  static drawStar(doc, x, y, outerRadius, innerRadius, r, g, b, alpha) {
    const points = 5; // 五角星
    const angleOffset = Math.PI / 2; // 从顶点开始
    
    // 设置颜色和透明度
    doc.saveGraphicsState();
    doc.setGState(new doc.GState({ opacity: alpha }));
    doc.setFillColor(r, g, b);
    
    // 构建星形路径
    const path = [];
    for (let i = 0; i < points * 2; i++) {
      const radius = i % 2 === 0 ? outerRadius : innerRadius;
      const angle = (i * Math.PI / points) - angleOffset;
      const pointX = x + radius * Math.cos(angle);
      const pointY = y + radius * Math.sin(angle);
      
      if (i === 0) {
        doc.moveTo(pointX, pointY);
      } else {
        doc.lineTo(pointX, pointY);
      }
    }
    
    // 闭合路径并填充
    doc.closePath().fill();
    doc.restoreGraphicsState();
  }

  /**
   * 安全地释放URL对象
   * @param {string} url - 由URL.createObjectURL创建的URL
   */
  static safeRevokeURL(url) {
    if (url && typeof url === 'string' && url.startsWith('blob:')) {
      try {
        URL.revokeObjectURL(url);
      } catch (error) {
        console.error('Failed to revoke object URL:', error);
      }
    }
  }
}

export default CertificateGenerator;
